class Cart():
    def __init__(self):
        self._items = []

    def addItem(self, item):
        self._items.append(item)

    def getItems(self):
        return self._items


class DiscountCode():
    def __init__(self):
        self._codes = {
            'FREE_SHIPPING': lambda: 0,
            'TEN_OFF': lambda price: max(price - 10, 0),
            'TWENTY_OFF': lambda price: max(price - 20, 0)
        }

    def getDiscountPrice(self, code):
        return self._codes[code]()


class TaxCalculator():
    def __init__(self):
        self.taxes = {
            'standard': .135
        }

    def calculateTax(self, price):
        return round(price * self.taxes['standard'], 2)


class OrderProcessor():
    def __init__(self, discountCode):
        self._discountCode = discountCode

        self._cart = Cart()
        self._taxCalculator = TaxCalculator()

    def addItemToCart(self, item):
        self._cart.addItem(item)

    def getDiscountedTotalPrice(self):
        price = 0

        for item in self._cart.getItems():
            price += item['price']

        return self._discountCode.getDiscountPrice(price)

    def getTotalTax(self):
        price = 0

        for item in self._cart.getItems():
            price += item['price']

        return self._taxCalculator.calculateTax(price)


class PaymentProcessor():
    def __init__(self):
        self._paymentTypes = {
            'cash': lambda price: True,
            'credit card': lambda price: False
        }

    def makePayment(self, price):
        return self._paymentTypes['credit card'](price)


